     4→import { createTodo, Priority } from '@/app/actions/todos';
     5→import { useState } from 'react';
     6→
     7→interface TodoFormData {
     8→  title: string;
     9→  description: string;
    10→  priority: Priority;
    11→  dueDate: string;
    12→}
    13→
    14→export default function TodoForm() {
    15→  const [isLoading, setIsLoading] = useState(false);
    16→  const {
    17→    register,
    18→    handleSubmit,
    19→    reset,
    20→    formState: { errors },
    21→  } = useForm<TodoFormData>({
    22→    defaultValues: {
    23→      priority: 'medium',
    24→    },
    25→  });
    26→
    27→  const onSubmit = async (data: TodoFormData) => {
    28→    setIsLoading(true);
    29→    try {
    30→      await createTodo({
    31→        title: data.title,
    32→        description: data.description || undefined,
    33→        priority: data.priority,
    34→        dueDate: data.dueDate ? new Date(data.dueDate) : undefined,
    35→      });
    36→      reset();
    37→    } catch (error) {
    38→      console.error('Failed to create todo:', error);
    39→    } finally {
    40→      setIsLoading(false);
    41→    }
    42→  };
    43→
    44→  return (
    45→    <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
    46→      <div>
    47→        <label htmlFor="title" className="block text-sm font-medium text-gray-700">
    48→          Title *
    49→        </label>
    50→        <input
    51→          id="title"
    52→          type="text"
    53→          {...register('title', {
    54→            required: 'Title is required',
    55→            validate: {
    56→              notEmpty: (value) => value.trim().length > 0 || 'Title is required',
    57→            },
    58→          })}
    59→          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 px-4 py-2 border text-gray-900 placeholder:text-gray-500"
    60→          placeholder="What needs to be done?"
    61→        />
    62→        {errors.title && (
    63→          <p className="mt-1 text-sm text-red-600">{errors.title.message}</p>
    64→        )}
    65→      </div>
    66→
    67→      <div>
    68→        <label htmlFor="description" className="block text-sm font-medium text-gray-700">
    69→          Description
    70→        </label>
    71→        <textarea
    72→          id="description"
    73→          {...register('description')}
    74→          rows={3}
    75→          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 px-4 py-2 border text-gray-900 placeholder:text-gray-500"
    76→          placeholder="Add more details..."
    77→        />
    78→      </div>
    79→
    80→      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
    81→        <div>
    82→          <label htmlFor="priority" className="block text-sm font-medium text-gray-700">
    83→            Priority
    84→          </label>
    85→          <select
